const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { buildSchema } = require('graphql');
const { Pool } = require('pg');
require('dotenv').config();

// PostgreSQL connection pool
const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  ssl: {
    rejectUnauthorized: false
  }
});

// GraphQL schema
const schema = buildSchema(`
  type Author {
    id: ID!
    name: String!
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    author: Author!
  }

  type Query {
    posts: [Post]
  }
`);

// Resolvers
const root = {
  posts: async () => {
    try {
      const client = await pool.connect();
      const res = await client.query('SELECT * FROM posts');
      const posts = res.rows;

      for (let post of posts) {
        const authorRes = await client.query('SELECT * FROM authors WHERE id = $1', [post.author_id]);
        post.author = authorRes.rows[0];
      }

      client.release();
      return posts;
    } catch (err) {
      console.error('Error fetching posts:', err);
      throw new Error('Failed to fetch posts');
    }
  }
};

// Express app
const app = express();

// GraphQL endpoint
app.use('/graphql', graphqlHTTP({
  schema: schema,
  rootValue: root,
  graphiql: false, // Disable GraphiQL in production for security
  customFormatErrorFn: (err) => {
    console.error('GraphQL Error:', err.message);
    return { message: 'Internal server error' };
  }
}));

// Start server
const PORT = process.env.PORT || 4000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});